"type": "text",
"text": "import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    N = int(input_data[0])
    targets = []
    idx = 1
    for _ in range(N):
        a = int(input_data[idx])
        b = int(input_data[idx+1])
        targets.append((a, b))
        idx += 2

    targets.sort()

    existing = [(0, 0)]
    operations = []

    for tx, ty in targets:
        best_dist = float('inf')
        best_source = None

        for fx, fy in existing:
            if fx <= tx and fy <= ty:
                dist = (tx - fx) + (ty - fy)
                if dist < best_dist:
                    best_dist = dist
                    best_source = (fx, fy)

        if best_source is None:
            best_source = (0, 0)
            best_dist = tx + ty

        operations.append((best_source[0], best_source[1], tx, ty))
        existing.append((tx, ty))

    print(len(operations))
    for op in operations:
        print(f"{op[0]} {op[1]} {op[2]} {op[3]}")

if __name__ == '__main__':
    solve()"
}
]
